render(() => {
const [suffix, setSuffix] = React.useState('currency');
const [minor, setMinor] = React.useState(true);
const [value, setValue] = React.useState(1234567);

const handleChange = (_, payload) => {
setValue(payload.value);
};

const suffixInput = {
currency: 'RUR',
percent: '%',
noSuffix: null,
}[suffix];

const onChangeSuffix = (_, payload) => {
setSuffix(payload.value);
};

const handleMinorChange = () => setMinor(!minor);

return (
<div style={{ width: isMobile() ? '100%' : 320 }}>
<AmountInput
value={value}
onChange={handleChange}
placeholder='Введите сумму'
labelView={isMobile() ? 'outer' : 'inner'}
label='Сумма'
minority={minor ? 100 : 1}
integersOnly={!minor}
bold={false}
suffix={suffixInput}
block={true}
size={isMobile() ? 48 : 56}
breakpoint={BREAKPOINT}
/>
<Gap size={24} />
<Switch label='Минорная часть' checked={minor} onChange={handleMinorChange} />
<Gap size={24} />
<RadioGroup
label='Суффикс'
direction='vertical'
name='radioGroup'
onChange={onChangeSuffix}
value={suffix}
>
<Radio size={24} label='Валюта' value='currency' />
<Radio size={24} label='Процент' value='percent' />
<Radio size={24} label='Нет' value='noSuffix' />
</RadioGroup>
</div>
);
});
